" return StreamingResponse(generate(), media_type="text/event-stream") return await service.handle_request(req.user_id, req.query, req.template) @app.get("/health") async def health(): return service.health_check() @app.get("/v1/costs") async def costs(): return service.cost_tracker.summary() @app.get("/v1/cache/stats") async def cache_stats(): return service.cache.stats() if __name__ == "__main__": uvicorn.run(app, host="0.0.0.0", port=8000) Real API Integration import openai import anthropic async def call_openai(prompt, model="gpt-4o"): client = openai.AsyncOpenAI() response = await client.chat.completions.create( model=model, messages=[{"role": "user", "content": prompt}], stream=True, ) full_text = "" async for chunk in response: delta = chunk.choices[0].delta.content or "" full_text += delta yield delta async def call_anthropic(prompt, model="claude-sonnet-4-20250514"): client = anthropic.AsyncAnthropic() async with client.messages.stream( model=model, max_tokens=1024, messages=[{"role": "user", "content": prompt}], ) as stream: async for text in stream.text_stream: yield text Docker Deployment FROM python:3.12-slim WORKDIR /app COPY requirements.txt . RUN pip install --no-cache-dir -r requirements.txt COPY . . EXPOSE 8000 CMD ["uvicorn", "production_app:app", "--host", "0.0.0.0", "--port", "8000", "--workers", "4"] Ship It Exercises Key Terms Further Reading
